2	
3	type Customer = {
4	  yearsWithMHPCO: number;
5	};
6	
7	type Item = {
8	  type: string;
9	  material?: string;
10	  cursed?: boolean;
11	  enchantment?: number;
12	};
13	
14	type Step = {
15	  op: string;
16	  items?: Item[];
17	};
18	
19	type ScenarioInput = {
20	  customer: Customer;
21	  steps: Step[];
22	};
23	
24	type ScenarioOutput = {
25	  results: unknown[];
26	};
27	
28	const PROCESSING_FEE = 5;
29	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
30	const CURSE_SURCHARGE_RATE = 0.5;
31	const HIGH_ENCHANTMENT_THRESHOLD = 5;
32	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
33	const LOYALTY_YEARS_THRESHOLD = 2;
34	const LOYALTY_DISCOUNT_RATE = 0.2;
35	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
36	const COMPONENT_BLOCK_SIZE = 3;
37	const COMPONENT_BLOCK_BASE_PREMIUM = 60;
38	
39	const BASE_PREMIUMS: Record<string, number> = {
40	  sword: 100,
41	  amulet: 60,
42	  staff: 80,
43	  potion: 40,
44	  rune: 25,
45	  moonstone: 25,
46	};
47	
48	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
49	
50	const isComponentBlock = (type: string, count: number): boolean =>
51	  COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE;
52	
53	const surchargeFor = (
54	  items: Item[],
55	  applies: (item: Item) => boolean,
56	  rate: number
57	): number =>
58	  items.reduce(
59	    (surcharge, item) =>
60	      applies(item) ? surcharge + BASE_PREMIUMS[item.type] * rate : surcharge,
61	    0
62	  );
63	
64	const isCursed = (item: Item): boolean => item.cursed === true;
65	
66	const isHighlyEnchanted = (item: Item): boolean =>
67	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
68	
69	const curseSurchargeFor = (items: Item[]): number =>
70	  surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
71	
72	const enchantmentSurchargeFor = (items: Item[]): number =>
73	  surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
74	
75	const groupBasePremium = (type: string, count: number): number =>
76	  isComponentBlock(type, count)
77	    ? COMPONENT_BLOCK_BASE_PREMIUM
78	    : count * BASE_PREMIUMS[type];
79	
80	const policyBaseFor = (items: Item[]): number => {
81	  const countsByType = new Map<string, number>();
82	  for (const item of items) {
83	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
84	  }
85	
86	  let policyBase = 0;
87	  for (const [type, count] of countsByType) {
88	    policyBase += groupBasePremium(type, count);
89	  }
90	  return policyBase;
91	};
92	
93	const qualifiesForLoyaltyDiscount = (customer: Customer): boolean =>
94	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
95	
96	const quotePremium = (
97	  items: Item[],
98	  customer: Customer,
99	  isFollowUp: boolean
100	): number => {
101	  const policyBase = policyBaseFor(items);
102	  const itemSurcharges =
103	    curseSurchargeFor(items) + enchantmentSurchargeFor(items);
104	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
105	  const loyaltyDiscount = qualifiesForLoyaltyDiscount(customer)
106	    ? policyBase * LOYALTY_DISCOUNT_RATE
107	    : 0;
108	  const followUpDiscount = isFollowUp
109	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
110	    : 0;
111	  return Math.ceil(
112	    policyBase +
113	      itemSurcharges +
114	      firstInsuranceSurcharge -
115	      loyaltyDiscount -
116	      followUpDiscount +
117	      PROCESSING_FEE
118	  );
119	};
120	
121	const isFollowUpQuote = (stepIndex: number): boolean => stepIndex > 0;
122	
123	export const processScenario = (input: ScenarioInput): ScenarioOutput => {
124	  const results = input.steps.map((step, index) => ({
125	    premium: quotePremium(step.items ?? [], input.customer, isFollowUpQuote(index)),
126	  }));
127	  return { results };
128	};
